import{_ as a,o as t,c as o,ai as d}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"网络模型","description":"","frontmatter":{"read_when":["你想要简要了解 Gateway 网关的网络模型"],"summary":"Gateway 网关、节点和 canvas 主机如何连接。","title":"网络模型","x-i18n":{"generated_at":"2026-02-04T17:53:21Z","model":"claude-opus-4-5","provider":"pi","source_hash":"e3508b884757ef19f425c82e891e2b07e7fd7d985413d569e55ae9b175c91f0f","source_path":"gateway/network-model.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/network-model.md","filePath":"zh-CN/gateway/network-model.md","lastUpdated":null}'),c={name:"zh-CN/gateway/network-model.md"};function l(n,e,s,r,i,w){return t(),o("div",null,[...e[0]||(e[0]=[d('<p>大多数操作通过 Gateway 网关（<code>opensoul gateway</code>）进行，它是一个长期运行的单一进程，负责管理渠道连接和 WebSocket 控制平面。</p><h2 id="核心规则" tabindex="-1"><a class="header-anchor" href="#核心规则">#</a> 核心规则</h2><ul><li>建议每台主机运行一个 Gateway 网关。它是唯一允许拥有 WhatsApp Web 会话的进程。对于救援机器人或严格隔离的场景，可以使用隔离的配置文件和端口运行多个 Gateway 网关。参见<a href="/docs/gateway/multiple-gateways">多 Gateway 网关</a>。</li><li>优先使用回环地址：Gateway 网关的 WS 默认为 <code>ws://127.0.0.1:18789</code>。即使是回环连接，向导也会默认生成 gateway token。若需通过 tailnet 访问，请运行 <code>opensoul gateway --bind tailnet --token ...</code>，因为非回环绑定必须使用 token。</li><li>节点根据需要通过局域网、tailnet 或 SSH 连接到 Gateway 网关的 WS。旧版 TCP 桥接已弃用。</li><li>Canvas 主机是一个 HTTP 文件服务器，运行在 <code>canvasHost.port</code>（默认 <code>18793</code>）上，提供 <code>/__opensoul__/canvas/</code> 路径供节点 WebView 使用。参见 <a href="/docs/gateway/configuration">Gateway 网关配置</a>（<code>canvasHost</code>）。</li><li>远程使用通常通过 SSH 隧道或 Tailscale VPN。参见<a href="/docs/gateway/remote">远程访问</a>和<a href="/docs/gateway/discovery">设备发现</a>。</li></ul>',3)])])}const y=a(c,[["render",l]]);export{p as __pageData,y as default};
